// === 内存采样监控（捕捉瞬间峰值） ===
window.MemorySampler = {
    lastSample: 0,
    lastTime: 0,
    sampleInterval: null,
    peakAlloc: 0,

    start() {
        if (!performance.memory) {
            console.warn(
                "[MemorySampler] ⚠️ 浏览器不支持 performance.memory API（需要在 Chrome DevTools 启用）",
            );
            console.warn(
                "[MemorySampler] 请尝试：Chrome 设置 → 开发者选项 → 启用 JS 堆大小统计",
            );
            return;
        }

        this.lastSample = performance.memory.usedJSHeapSize;
        this.lastTime = performance.now();

        console.log(
            "[MemorySampler] ✅ 采样已启动，当前堆：" +
            (this.lastSample / 1024 / 1024).toFixed(1) +
            "MB",
        );

        this.sampleInterval = setInterval(() => {
            try {
                const now = performance.now();
                const heapNow = performance.memory.usedJSHeapSize;
                const timeDelta = now - this.lastTime; // ms
                const heapDelta = heapNow - this.lastSample; // bytes

                if (heapDelta !== 0) {
                    const deltaKB = heapDelta / 1024;
                    const deltaMB = heapDelta / 1024 / 1024;
                    const speedMBps = deltaMB / (timeDelta / 1000); // MB/s

                    // 更低的门槛，任何变化都记录
                    const direction = heapDelta > 0 ? "📈 +" : "📉 ";
                    console.log(
                        `[HEAP] ${direction}${Math.abs(deltaKB).toFixed(0)}KB | 速率: ${Math.abs(speedMBps).toFixed(2)}MB/s | 当前: ${(heapNow / 1024 / 1024).toFixed(1)}MB`,
                    );

                    // 危险预警
                    if (speedMBps > 5) {
                        console.error(
                            "🚨 [DANGER] 分配速率超过 5MB/s！！",
                            new Error().stack.split("\n").slice(0, 5).join("\n"),
                        );
                    }
                }

                this.lastSample = heapNow;
                this.lastTime = now;
            } catch (e) {
                console.error("[MemorySampler] 采样出错:", e);
            }
        }, 100); // 100ms 采样一次，更频繁

        console.log("[MemorySampler] 采样已启动！每 100ms 输出一次内存变化");
    },

    stop() {
        if (this.sampleInterval) {
            clearInterval(this.sampleInterval);
            console.log("[MemorySampler] 采样已停止");
        }
    },
};

