// === 全能API请求适配器 ===
// 自动兼容 OpenAI 格式和 Gemini 官方 API
// 增强版：支持智能格式检测和自动重试

// API 格式缓存：记住每个端点的正确格式，避免重复试错
const _apiFormatCache = {};

/**
 * 检测 URL 是否应该使用 Gemini 原生格式
 * @param {string} url - API URL
 * @returns {boolean} - 是否为 Gemini 原生格式
 */
function _detectGeminiNative(url) {
    // 1. 检查缓存
    const cacheKey = new URL(url, 'https://placeholder.com').origin;
    if (_apiFormatCache[cacheKey] !== undefined) {
        console.log(`[UniversalAPI] 使用缓存的格式: ${_apiFormatCache[cacheKey] ? 'Gemini' : 'OpenAI'}`);
        return _apiFormatCache[cacheKey];
    }

    // 2. URL 特征检测
    if (url.includes("generativelanguage.googleapis.com") ||
        url.includes("googleapis.com/v1beta") ||
        url.includes("googleapis.com/v1alpha")) {
        return true;
    }

    // 3. 模型名称检测（某些中转站 URL 中包含模型名）
    if (url.includes("/gemini-") || url.includes(":generateContent")) {
        return true;
    }

    return false;
}

/**
 * 缓存 API 格式
 */
function _cacheApiFormat(url, isGemini) {
    try {
        const cacheKey = new URL(url, 'https://placeholder.com').origin;
        _apiFormatCache[cacheKey] = isGemini;
        console.log(`[UniversalAPI] 已缓存 API 格式: ${cacheKey} -> ${isGemini ? 'Gemini' : 'OpenAI'}`);
    } catch (e) {
        // 忽略无效 URL
    }
}

/**
 * 构建 Gemini 原生请求
 */
function _buildGeminiRequest(config, messages, options) {
    const { url, key, model, temperature } = config;
    const { maxTokens = 4096, customTemperature } = options;

    // 构造 Gemini 原生 URL
    let endpoint = url.replace(/\/+$/, '');
    endpoint = endpoint.replace(/\/v1beta\/models\/.*$/, '');
    endpoint = endpoint.replace(/\/v1\/.*$/, '');
    endpoint = endpoint.replace(/\/models\/.*$/, '');
    endpoint = endpoint.replace(/\/chat\/completions$/, '');
    if (!endpoint.includes('/v1beta')) {
        endpoint = endpoint.replace(/\/?$/, '') + '/v1beta';
    }
    endpoint = `${endpoint}/models/${model}:generateContent?key=${key}`;

    // 转换消息格式
    let systemContent = "";
    const geminiContents = [];

    for (const msg of messages) {
        if (msg.role === "system") {
            systemContent += (systemContent ? "\n\n" : "") + (typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content));
        } else {
            let parts = [];
            if (typeof msg.content === 'string') {
                parts.push({ text: msg.content });
            } else if (Array.isArray(msg.content)) {
                for (const item of msg.content) {
                    if (item.type === 'text') {
                        parts.push({ text: item.text });
                    } else if (item.type === 'image_url') {
                        parts.push({ text: "[图片消息 - Gemini 原生模式暂不支持]" });
                    }
                }
            }
            geminiContents.push({
                role: msg.role === "assistant" ? "model" : "user",
                parts: parts
            });
        }
    }

    const body = {
        contents: geminiContents,
        generationConfig: {
            temperature: customTemperature !== undefined ? customTemperature : (parseFloat(temperature) || 1),
            maxOutputTokens: maxTokens
        }
    };

    if (systemContent) {
        body.systemInstruction = { parts: [{ text: systemContent }] };
    }

    return {
        endpoint,
        headers: { "Content-Type": "application/json" },
        body
    };
}

/**
 * 构建 OpenAI 兼容请求
 */
function _buildOpenAIRequest(config, messages, options) {
    const { url, key, model, temperature } = config;
    const { maxTokens = 4096, customTemperature } = options;

    let endpoint = url.replace(/\/+$/, '');
    if (!endpoint.endsWith('/chat/completions')) {
        endpoint += "/chat/completions";
    }

    return {
        endpoint,
        headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer ${key}`
        },
        body: {
            model,
            messages,
            temperature: customTemperature !== undefined ? customTemperature : (parseFloat(temperature) || 1),
            max_tokens: maxTokens
        }
    };
}

/**
 * 解析 Gemini 响应为 OpenAI 格式
 */
function _parseGeminiResponse(data) {
    if (data.candidates && data.candidates.length > 0) {
        const candidate = data.candidates[0];

        if (candidate.finishReason === "SAFETY") {
            throw new Error("内容被 Gemini 安全策略拦截。请调整人设或输入内容。");
        }

        let textContent = "";
        if (candidate.content && candidate.content.parts) {
            for (const part of candidate.content.parts) {
                if (part.text) textContent += part.text;
            }
        }

        return {
            choices: [{
                message: { role: "assistant", content: textContent },
                finish_reason: candidate.finishReason?.toLowerCase() || "stop"
            }],
            usage: data.usageMetadata ? {
                prompt_tokens: data.usageMetadata.promptTokenCount,
                completion_tokens: data.usageMetadata.candidatesTokenCount,
                total_tokens: data.usageMetadata.totalTokenCount
            } : null
        };
    } else if (data.promptFeedback && data.promptFeedback.blockReason) {
        throw new Error(`Gemini 拒绝生成 (Reason: ${data.promptFeedback.blockReason})。`);
    } else {
        throw new Error("Gemini API 返回了空内容。请检查模型名称是否正确。");
    }
}

/**
 * 执行单次 API 请求
 */
async function _executeRequest(endpoint, headers, body) {
    const response = await fetch(endpoint, {
        method: "POST",
        headers,
        body: JSON.stringify(body)
    });

    if (!response.ok) {
        let errDetail = "";
        try {
            const errJson = await response.json();
            errDetail = errJson.error?.message || JSON.stringify(errJson);
        } catch (e) {
            try { errDetail = await response.text(); } catch (txtErr) { errDetail = "无法读取错误详情"; }
        }
        throw { status: response.status, detail: errDetail };
    }

    return await response.json();
}

/**
 * 全能 API 请求适配器 - 主函数
 * 支持智能格式检测和自动重试
 */
async function universalApiRequest(config, messages, options = {}) {
    const { url, model } = config;

    // 1. 检测初始格式
    let useGemini = _detectGeminiNative(url);

    // 2. 构建请求
    let request = useGemini
        ? _buildGeminiRequest(config, messages, options)
        : _buildOpenAIRequest(config, messages, options);

    console.log(`[UniversalAPI] 请求模式: ${useGemini ? 'Gemini Native' : 'OpenAI Compatible'}`);
    console.log(`[UniversalAPI] Endpoint: ${request.endpoint.substring(0, 80)}...`);

    try {
        // 3. 执行请求
        const data = await _executeRequest(request.endpoint, request.headers, request.body);

        // 4. 缓存成功的格式
        _cacheApiFormat(url, useGemini);

        // 5. 解析响应
        if (useGemini) {
            return _parseGeminiResponse(data);
        }
        return data;

    } catch (error) {
        // 6. 智能重试：如果 OpenAI 格式失败（404/405），尝试 Gemini 格式
        if (!useGemini && error.status && (error.status === 404 || error.status === 405)) {
            console.warn(`[UniversalAPI] OpenAI 格式失败 (${error.status})，尝试 Gemini 格式...`);

            try {
                const geminiRequest = _buildGeminiRequest(config, messages, options);
                console.log(`[UniversalAPI] 重试 Gemini: ${geminiRequest.endpoint.substring(0, 80)}...`);

                const data = await _executeRequest(geminiRequest.endpoint, geminiRequest.headers, geminiRequest.body);

                // 缓存成功的格式
                _cacheApiFormat(url, true);
                console.log(`[UniversalAPI] Gemini 格式成功！已缓存。`);

                return _parseGeminiResponse(data);
            } catch (retryError) {
                console.error(`[UniversalAPI] Gemini 格式也失败:`, retryError);
                // 继续抛出原始错误
            }
        }

        // 7. 智能重试：如果 Gemini 格式失败，尝试 OpenAI 格式
        if (useGemini && error.status && (error.status === 404 || error.status === 400)) {
            console.warn(`[UniversalAPI] Gemini 格式失败 (${error.status})，尝试 OpenAI 格式...`);

            try {
                const openaiRequest = _buildOpenAIRequest(config, messages, options);
                console.log(`[UniversalAPI] 重试 OpenAI: ${openaiRequest.endpoint.substring(0, 80)}...`);

                const data = await _executeRequest(openaiRequest.endpoint, openaiRequest.headers, openaiRequest.body);

                // 缓存成功的格式
                _cacheApiFormat(url, false);
                console.log(`[UniversalAPI] OpenAI 格式成功！已缓存。`);

                return data;
            } catch (retryError) {
                console.error(`[UniversalAPI] OpenAI 格式也失败:`, retryError);
            }
        }

        // 8. 转换错误信息
        if (error.detail) {
            if (error.detail.includes("SAFETY") || error.detail.includes("BLOCK")) {
                throw new Error(`API 安全拦截: 内容触发了安全审查。\n详情: ${error.detail.slice(0, 200)}`);
            }
            if (error.detail.includes("context_length_exceeded") || error.detail.includes("max.*token")) {
                throw new Error(`上下文长度溢出: 内容太长了。\n详情: ${error.detail.slice(0, 200)}`);
            }
            throw new Error(`API请求失败 (HTTP ${error.status}):\n${error.detail.slice(0, 200)}`);
        }

        throw error;
    }
}

// 将适配器暴露到全局
window.universalApiRequest = universalApiRequest;

// 暴露缓存清理函数（用于调试或设置更改时）
window.clearApiFormatCache = function () {
    Object.keys(_apiFormatCache).forEach(k => delete _apiFormatCache[k]);
    console.log('[UniversalAPI] 格式缓存已清空');
};

/**
 * 流式 API 请求适配器 - 支持 OpenAI 和 Gemini 两种 API 格式的流式响应
 * @param {Object} apiSettings - API 设置对象 (url, key, model, temperature, maxTokens)
 * @param {Array} messages - 消息数组
 * @param {Object} options - 额外选项 (customTemperature, onChunk 回调)
 * @returns {Promise<string>} - 返回完整的文本内容
 */
async function universalApiStreamRequest(apiSettings, messages, options = {}) {
    const { url, key, model, temperature, maxTokens } = apiSettings;
    const { customTemperature, onChunk } = options;

    // 使用与非流式适配器相同的格式检测逻辑
    const useGemini = _detectGeminiNative(url);

    let endpoint = url;
    let headers = { "Content-Type": "application/json" };
    let body;

    if (useGemini) {
        // Gemini 流式模式使用 streamGenerateContent
        let baseUrl = url.replace(/\/+$/, '');
        baseUrl = baseUrl.replace(/\/v1beta\/models\/.*$/, '');
        baseUrl = baseUrl.replace(/\/v1\/.*$/, '');
        baseUrl = baseUrl.replace(/\/models\/.*$/, '');
        baseUrl = baseUrl.replace(/\/chat\/completions$/, '');
        if (!baseUrl.includes('/v1beta')) {
            baseUrl = baseUrl.replace(/\/?$/, '') + '/v1beta';
        }
        const modelName = model || 'gemini-2.0-flash';
        endpoint = `${baseUrl}/models/${modelName}:streamGenerateContent?key=${key}&alt=sse`;

        // 转换 OpenAI 格式消息为 Gemini 格式
        const contents = [];
        let systemInstruction = null;
        for (const msg of messages) {
            if (msg.role === 'system') {
                systemInstruction = { parts: [{ text: msg.content }] };
            } else {
                contents.push({
                    role: msg.role === 'assistant' ? 'model' : 'user',
                    parts: [{ text: msg.content }]
                });
            }
        }

        body = {
            contents,
            generationConfig: {
                temperature: customTemperature !== undefined ? customTemperature : (parseFloat(temperature) || 1),
                maxOutputTokens: maxTokens || 4096
            }
        };
        if (systemInstruction) {
            body.systemInstruction = systemInstruction;
        }
    } else {
        // OpenAI 流式模式
        if (!endpoint.endsWith('/chat/completions')) {
            endpoint = endpoint.replace(/\/+$/, '') + "/chat/completions";
        }
        headers["Authorization"] = `Bearer ${key}`;
        headers["Accept"] = "text/event-stream";
        headers["Cache-Control"] = "no-cache";
        body = {
            model,
            messages,
            temperature: customTemperature !== undefined ? customTemperature : (parseFloat(temperature) || 1),
            max_tokens: maxTokens || 4096,
            stream: true
        };
    }

    console.log(`[UniversalStreamAPI] 请求模式: ${useGemini ? 'Gemini Native' : 'OpenAI Compatible'}`);

    const response = await fetch(endpoint, {
        method: "POST",
        headers,
        body: JSON.stringify(body)
    });

    if (!response.ok) {
        let errDetail = "";
        try {
            const errJson = await response.json();
            errDetail = errJson.error?.message || JSON.stringify(errJson);
        } catch (e) {
            try { errDetail = await response.text(); } catch (txtErr) { errDetail = "无法读取错误详情"; }
        }
        throw new Error(`API请求失败 (HTTP ${response.status}):\n${errDetail.slice(0, 200)}`);
    }

    // 流式读取
    const reader = response.body.getReader();
    const decoder = new TextDecoder("utf-8");
    let done = false;
    let fullText = "";
    let buffer = ""; // 处理不完整的行

    while (!done) {
        const { value, done: readerDone } = await reader.read();
        done = readerDone;
        if (value) {
            buffer += decoder.decode(value, { stream: true });
            const lines = buffer.split("\n");
            buffer = lines.pop() || ""; // 保留最后一个可能不完整的行

            for (const line of lines) {
                if (!line.trim()) continue;

                if (useGemini) {
                    // Gemini SSE 格式: data: {"candidates":[...]}
                    if (line.startsWith("data: ")) {
                        try {
                            const json = JSON.parse(line.substring(6));
                            if (json.candidates && json.candidates[0]?.content?.parts) {
                                for (const part of json.candidates[0].content.parts) {
                                    if (part.text) {
                                        fullText += part.text;
                                        if (onChunk) onChunk(part.text);
                                    }
                                }
                            }
                        } catch (e) {
                            // 忽略解析错误
                        }
                    }
                } else {
                    // OpenAI SSE 格式: data: {"choices":[{"delta":{"content":"..."}}]}
                    if (line.startsWith("data: ") && line !== "data: [DONE]") {
                        try {
                            const json = JSON.parse(line.substring(6));
                            if (json.choices && json.choices[0]?.delta?.content) {
                                const content = json.choices[0].delta.content;
                                fullText += content;
                                if (onChunk) onChunk(content);
                            }
                        } catch (e) {
                            // 忽略解析错误
                        }
                    }
                }
            }
        }
    }

    console.log(`[UniversalStreamAPI] 流式完成，总长度: ${fullText.length}`);
    return fullText;
}

// 暴露流式适配器到全局
window.universalApiStreamRequest = universalApiStreamRequest;

